package com.example.slagalica.data.model;

import androidx.annotation.NonNull;

import java.util.List;

/**
 * Firestore POJO koji predstavlja jedan zadatak za igru "Korak po korak".
 *
 * <p>Čuva se u Firestore kolekciji {@code korakPoKorak}.
 * Lista {@code koraci} sadrži tačno 7 hintova — indeks 0 je najteži
 * (donosi 20 poena), indeks 6 je najlakši (donosi 8 poena).</p>
 *
 * <p>Firestore zahteva: public no-arg konstruktor, public getteri i setteri,
 * bez {@code final} polja.</p>
 */
public class KorakPoKorakZadatak {

    /** Firestore document ID. */
    private String id;

    /** Tačno rešenje — odgovor koji igrač treba da pogodi. */
    private String resenje;

    /**
     * Lista od tačno 7 hintova.
     * Indeks 0 = najteži hint (prvi koji se prikazuje, 20 poena).
     * Indeks 6 = najlakši hint (poslednji, 8 poena).
     */
    private List<String> koraci;

    // -------------------------------------------------------------------------
    // Konstruktori
    // -------------------------------------------------------------------------

    /** Prazan konstruktor — obavezan za Firestore deserijalizaciju. */
    public KorakPoKorakZadatak() {
    }

    /**
     * Konstruktor sa svim poljima.
     *
     * @param id      Firestore document ID
     * @param resenje tačno rešenje zadatka
     * @param koraci  lista od tačno 7 hintova (od najtežeg ka najlakšem)
     */
    public KorakPoKorakZadatak(String id, String resenje, List<String> koraci) {
        this.id = id;
        this.resenje = resenje;
        this.koraci = koraci;
    }

    // -------------------------------------------------------------------------
    // Getteri
    // -------------------------------------------------------------------------

    public String getId() {
        return id;
    }

    public String getResenje() {
        return resenje;
    }

    public List<String> getKoraci() {
        return koraci;
    }

    // -------------------------------------------------------------------------
    // Setteri
    // -------------------------------------------------------------------------

    public void setId(String id) {
        this.id = id;
    }

    public void setResenje(String resenje) {
        this.resenje = resenje;
    }

    public void setKoraci(List<String> koraci) {
        this.koraci = koraci;
    }

    // -------------------------------------------------------------------------
    // toString
    // -------------------------------------------------------------------------

    @NonNull
    @Override
    public String toString() {
        return "KorakPoKorakZadatak{" +
                "id='" + id + '\'' +
                ", resenje='" + resenje + '\'' +
                ", koraci=" + koraci +
                '}';
    }
}

package com.example.slagalica.data.model;

/**
 * POJO klasa koja predstavlja korisnika aplikacije.
 * Koristi se za čitanje/pisanje u Firestore kolekciji "users".
 *
 * <p>Firestore zahteva: public no-arg konstruktor, public getteri i setteri,
 * bez final polja.</p>
 */
public class User {

    private String uid;
    private String email;
    private String username;
    private String region;
    /** URL slike avatara. Ako je null, koristi se lokalni default placeholder. */
    private String avatarUrl;
    private int tokens;
    private int totalStars;
    private int currentLeague;
    /** Unix timestamp (ms) poslednjeg dodeljivanja dnevnih tokena. */
    private long lastTokenGrantTimestamp;
    /** Unix timestamp (ms) kreiranja naloga. */
    private long createdAt;
    /**
     * Tip okvira avatara:
     * 0 = default, 1 = zlatni, 2 = srebrni, 3 = bronzani.
     */
    private int avatarFrameType;

    // -------------------------------------------------------------------------
    // Konstruktori
    // -------------------------------------------------------------------------

    /** Prazan konstruktor — obavezan za Firestore deserijalizaciju. */
    public User() {
        this.tokens = 5;
        this.totalStars = 0;
        this.currentLeague = 0;
        this.avatarFrameType = 0;
    }

    /**
     * Konstruktor sa svim poljima.
     *
     * @param uid                      Firebase Auth UID
     * @param email                    email adresa korisnika
     * @param username                 korisničko ime
     * @param region                   region (npr. "Beograd")
     * @param avatarUrl                URL avatara, može biti null
     * @param tokens                   trenutni broj tokena
     * @param totalStars               ukupan broj zvezda
     * @param currentLeague            trenutna liga (0 = bronzana, itd.)
     * @param lastTokenGrantTimestamp  timestamp poslednjeg dodeljivanja tokena (ms)
     * @param createdAt                timestamp kreiranja naloga (ms)
     * @param avatarFrameType          tip okvira avatara (0–3)
     */
    public User(String uid, String email, String username, String region,
                String avatarUrl, int tokens, int totalStars, int currentLeague,
                long lastTokenGrantTimestamp, long createdAt, int avatarFrameType) {
        this.uid = uid;
        this.email = email;
        this.username = username;
        this.region = region;
        this.avatarUrl = avatarUrl;
        this.tokens = tokens;
        this.totalStars = totalStars;
        this.currentLeague = currentLeague;
        this.lastTokenGrantTimestamp = lastTokenGrantTimestamp;
        this.createdAt = createdAt;
        this.avatarFrameType = avatarFrameType;
    }

    // -------------------------------------------------------------------------
    // Getteri
    // -------------------------------------------------------------------------

    public String getUid() {
        return uid;
    }

    public String getEmail() {
        return email;
    }

    public String getUsername() {
        return username;
    }

    public String getRegion() {
        return region;
    }

    public String getAvatarUrl() {
        return avatarUrl;
    }

    public int getTokens() {
        return tokens;
    }

    public int getTotalStars() {
        return totalStars;
    }

    public int getCurrentLeague() {
        return currentLeague;
    }

    public long getLastTokenGrantTimestamp() {
        return lastTokenGrantTimestamp;
    }

    public long getCreatedAt() {
        return createdAt;
    }

    public int getAvatarFrameType() {
        return avatarFrameType;
    }

    // -------------------------------------------------------------------------
    // Setteri
    // -------------------------------------------------------------------------

    public void setUid(String uid) {
        this.uid = uid;
    }

    public void setEmail(String email) {
        this.email = email;
    }

    public void setUsername(String username) {
        this.username = username;
    }

    public void setRegion(String region) {
        this.region = region;
    }

    public void setAvatarUrl(String avatarUrl) {
        this.avatarUrl = avatarUrl;
    }

    public void setTokens(int tokens) {
        this.tokens = tokens;
    }

    public void setTotalStars(int totalStars) {
        this.totalStars = totalStars;
    }

    public void setCurrentLeague(int currentLeague) {
        this.currentLeague = currentLeague;
    }

    public void setLastTokenGrantTimestamp(long lastTokenGrantTimestamp) {
        this.lastTokenGrantTimestamp = lastTokenGrantTimestamp;
    }

    public void setCreatedAt(long createdAt) {
        this.createdAt = createdAt;
    }

    public void setAvatarFrameType(int avatarFrameType) {
        this.avatarFrameType = avatarFrameType;
    }

    // -------------------------------------------------------------------------
    // toString
    // -------------------------------------------------------------------------

    @Override
    public String toString() {
        return "User{" +
                "uid='" + uid + '\'' +
                ", email='" + email + '\'' +
                ", username='" + username + '\'' +
                ", region='" + region + '\'' +
                ", avatarUrl='" + avatarUrl + '\'' +
                ", tokens=" + tokens +
                ", totalStars=" + totalStars +
                ", currentLeague=" + currentLeague +
                ", lastTokenGrantTimestamp=" + lastTokenGrantTimestamp +
                ", createdAt=" + createdAt +
                ", avatarFrameType=" + avatarFrameType +
                '}';
    }
}

package com.example.slagalica.data.repository;

import androidx.annotation.NonNull;

import com.example.slagalica.data.model.KorakPoKorakZadatak;
import com.google.firebase.firestore.FirebaseFirestore;
import com.google.firebase.firestore.QueryDocumentSnapshot;
import com.google.firebase.firestore.QuerySnapshot;

import java.util.ArrayList;
import java.util.List;
import java.util.Random;

/**
 * Singleton repozitorijum za učitavanje sadržaja igara iz Firestore-a.
 *
 * <p><b>Važno:</b> Sve Firestore kolekcije moraju biti popunjene ručno
 * ili putem seed skripte pre prvog korišćenja aplikacije. Kolekcije koje
 * ovaj repozitorijum koristi:</p>
 * <ul>
 *   <li>{@code korakPoKorak} — zadaci za igru "Korak po korak"</li>
 *   <li>{@code koZnaZna} — pitanja za "Ko zna zna" (Student 2)</li>
 * </ul>
 *
 * <p>Svaki dokument mora imati strukturu koja odgovara odgovarajućem POJO modelu.</p>
 */
public class GameContentRepository {

    private static final String COLLECTION_KORAK   = "korakPoKorak";
    private static final String COLLECTION_KO_ZNA  = "koZnaZna";

    // -------------------------------------------------------------------------
    // Singleton
    // -------------------------------------------------------------------------

    private static GameContentRepository instance;

    private final FirebaseFirestore mDb;
    private final Random random;

    private GameContentRepository() {
        mDb = FirebaseFirestore.getInstance();
        random = new Random();
    }

    /**
     * Vraća jedinu instancu {@link GameContentRepository}.
     *
     * @return singleton instanca
     */
    public static synchronized GameContentRepository getInstance() {
        if (instance == null) {
            instance = new GameContentRepository();
        }
        return instance;
    }

    // -------------------------------------------------------------------------
    // Callback interfejsi
    // -------------------------------------------------------------------------

    /** Callback za učitavanje zadatka za igru "Korak po korak". */
    public interface KorakLoadCallback {
        void onSuccess(KorakPoKorakZadatak zadatak);
        void onError(String message);
    }

    /**
     * Generički callback za jednostavan uspeh/greška signal.
     * Koristi se za placeholder metode dok ih studenti ne implementiraju.
     */
    public interface SimpleCallback {
        void onSuccess();
        void onError(String message);
    }

    // -------------------------------------------------------------------------
    // Korak po korak
    // -------------------------------------------------------------------------

    /**
     * Učitava slučajno izabrani zadatak iz Firestore kolekcije {@code korakPoKorak}.
     *
     * <p>Implementacija učitava sve dokumente, pa bira nasumičan.
     * Ovo je prihvatljivo dok je broj zadataka mali (desetine). Za veće
     * kolekcije razmotriti paginaciju ili server-side random selection.</p>
     *
     * <p><b>Preduslov:</b> kolekcija {@code korakPoKorak} mora biti popunjena
     * pre poziva ove metode — aplikacija ne seeduje podatke automatski.</p>
     *
     * @param cb callback koji prima {@link KorakPoKorakZadatak} pri uspehu,
     *           ili poruku greške pri neuspehu
     */
    public void getRandomKorakPoKorak(@NonNull KorakLoadCallback cb) {
        mDb.collection(COLLECTION_KORAK)
                .get()
                .addOnSuccessListener((QuerySnapshot querySnapshot) -> {
                    if (querySnapshot.isEmpty()) {
                        cb.onError("Nema dostupnih zadataka. Kontaktiraj administratora.");
                        return;
                    }

                    List<QueryDocumentSnapshot> docs = new ArrayList<>();
                    for (QueryDocumentSnapshot doc : querySnapshot) {
                        docs.add(doc);
                    }

                    // Slučajan odabir dokumenta
                    QueryDocumentSnapshot chosen = docs.get(random.nextInt(docs.size()));
                    KorakPoKorakZadatak zadatak = chosen.toObject(KorakPoKorakZadatak.class);

                    if (zadatak == null) {
                        cb.onError("Greška pri čitanju zadatka. Pokušaj ponovo.");
                        return;
                    }

                    // Postavi ID iz document reference (nije serijalizovano automatski)
                    zadatak.setId(chosen.getId());
                    cb.onSuccess(zadatak);
                })
                .addOnFailureListener(e ->
                        cb.onError("Greška pri učitavanju zadatka. Proveri internet vezu."));
    }

    // -------------------------------------------------------------------------
    // Ko zna zna — placeholder (Student 2)
    // -------------------------------------------------------------------------

    /**
     * Učitava slučajno pitanje za igru "Ko zna zna" iz kolekcije {@code koZnaZna}.
     *
     * <p><b>TODO (Student 2):</b> Implementirati ovu metodu kada bude definisan
     * POJO model za pitanja "Ko zna zna". Isti obrazac kao
     * {@link #getRandomKorakPoKorak(KorakLoadCallback)}.</p>
     *
     * @param cb callback — trenutno uvek vraća grešku (nije implementirano)
     */
    public void getRandomKoZnaZna(@NonNull SimpleCallback cb) {
        // TODO (Student 2): implementirati učitavanje pitanja iz kolekcije "koZnaZna"
        // Obrazac:
        // mDb.collection(COLLECTION_KO_ZNA).get()
        //     .addOnSuccessListener(snapshot -> { ... cb.onSuccess(); })
        //     .addOnFailureListener(e -> cb.onError(...));
        cb.onError("getRandomKoZnaZna nije još implementirano.");
    }

    // -------------------------------------------------------------------------
    // Moj broj — placeholder
    // -------------------------------------------------------------------------

    /**
     * Učitava preset rundu za igru "Moj broj" (opciono — igra generiše brojeve
     * i lokalno, pa ovo može ostati nepopunjeno).
     *
     * <p><b>TODO:</b> Implementirati ako se žele predefinisane runde sa serverski
     * generisanim brojevima umesto nasumičnih lokalnih.</p>
     *
     * @param cb callback — trenutno uvek vraća grešku (nije implementirano)
     */
    public void getRandomMojBroj(@NonNull SimpleCallback cb) {
        // TODO: implementirati ako se koriste server-side preset runde za "Moj broj"
        // Za KT2 igra generiše brojeve lokalno u MojBrojActivity.generisi6Brojeva()
        cb.onError("getRandomMojBroj nije implementirano — koristi se lokalna generacija.");
    }
}

package com.example.slagalica.data.repository;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;

import com.example.slagalica.data.model.User;
import com.google.firebase.auth.AuthCredential;
import com.google.firebase.auth.EmailAuthProvider;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.auth.FirebaseAuthInvalidCredentialsException;
import com.google.firebase.auth.FirebaseAuthInvalidUserException;
import com.google.firebase.auth.FirebaseAuthUserCollisionException;
import com.google.firebase.auth.FirebaseAuthWeakPasswordException;
import com.google.firebase.auth.FirebaseUser;
import com.google.firebase.firestore.FirebaseFirestore;
import com.google.firebase.firestore.QueryDocumentSnapshot;

/**
 * Singleton repozitorijum koji upravlja svim operacijama vezanim za
 * autentifikaciju i korisničke podatke.
 *
 * <p>Koristi Firebase Auth za autentifikaciju i Firestore kolekciju
 * "users" za profile korisnika.</p>
 *
 * <p>Sve metode su asinhrone i komuniciraju s UI slojem isključivo
 * putem callback interfejsa — nikad ne vraćaju {@code Task<>} direktno.</p>
 */
public class UserRepository {

    private static final String COLLECTION_USERS = "users";

    // -------------------------------------------------------------------------
    // Singleton
    // -------------------------------------------------------------------------

    private static UserRepository instance;

    private final FirebaseAuth mAuth;
    private final FirebaseFirestore mDb;

    private UserRepository() {
        mAuth = FirebaseAuth.getInstance();
        mDb = FirebaseFirestore.getInstance();
    }

    /**
     * Vraća jedinu instancu {@link UserRepository}.
     *
     * @return singleton instanca
     */
    public static synchronized UserRepository getInstance() {
        if (instance == null) {
            instance = new UserRepository();
        }
        return instance;
    }

    // -------------------------------------------------------------------------
    // Callback interfejsi
    // -------------------------------------------------------------------------

    /** Callback za operacije koje vraćaju {@link FirebaseUser} pri uspehu. */
    public interface AuthCallback {
        void onSuccess(FirebaseUser user);
        void onError(String message);
    }

    /** Callback za operacije koje vraćaju {@link User} POJO pri uspehu. */
    public interface UserCallback {
        void onSuccess(User user);
        void onError(String message);
    }

    // -------------------------------------------------------------------------
    // Registracija
    // -------------------------------------------------------------------------

    /**
     * Registruje novog korisnika:
     * <ol>
     *   <li>Proveri jedinstvenost korisničkog imena u Firestore-u.</li>
     *   <li>Kreira Firebase Auth nalog.</li>
     *   <li>Šalje email verifikaciju.</li>
     *   <li>Upisuje {@link User} dokument u Firestore.</li>
     * </ol>
     *
     * @param email    email adresa
     * @param username željeno korisničko ime (mora biti jedinstveno)
     * @param region   izabrani region
     * @param password lozinka
     * @param cb       callback sa rezultatom operacije
     */
    public void register(@NonNull String email,
                         @NonNull String username,
                         @NonNull String region,
                         @NonNull String password,
                         @NonNull AuthCallback cb) {

        // Korak 1: proveri jedinstvenost korisničkog imena
        mDb.collection(COLLECTION_USERS)
                .whereEqualTo("username", username)
                .get()
                .addOnSuccessListener(querySnapshot -> {
                    if (!querySnapshot.isEmpty()) {
                        cb.onError("Korisničko ime je već zauzeto.");
                        return;
                    }
                    // Korak 2: kreiraj Firebase Auth nalog
                    createAuthUser(email, username, region, password, cb);
                })
                .addOnFailureListener(e ->
                        cb.onError("Greška pri proveri korisničkog imena. Pokušaj ponovo."));
    }

    /** Pomoćna metoda — kreira Auth nalog nakon provere korisničkog imena. */
    private void createAuthUser(String email, String username, String region,
                                String password, AuthCallback cb) {
        mAuth.createUserWithEmailAndPassword(email, password)
                .addOnSuccessListener(authResult -> {
                    FirebaseUser firebaseUser = authResult.getUser();
                    if (firebaseUser == null) {
                        cb.onError("Greška pri kreaciji naloga. Pokušaj ponovo.");
                        return;
                    }

                    // Korak 3: pošalji email verifikaciju
                    firebaseUser.sendEmailVerification()
                            .addOnFailureListener(e -> {
                                // Ne blokiraj registraciju ako verifikacija ne uspe
                            });

                    // Korak 4: upiši User profil u Firestore
                    saveUserToFirestore(firebaseUser, email, username, region, cb);
                })
                .addOnFailureListener(e -> cb.onError(mapAuthError(e)));
    }

    /** Pomoćna metoda — upisuje novi {@link User} dokument u Firestore. */
    private void saveUserToFirestore(FirebaseUser firebaseUser, String email,
                                     String username, String region, AuthCallback cb) {
        long now = System.currentTimeMillis();
        User user = new User(
                firebaseUser.getUid(),
                email,
                username,
                region,
                null,   // avatarUrl — null, koristi se lokalni placeholder
                5,      // tokens
                0,      // totalStars
                0,      // currentLeague
                now,    // lastTokenGrantTimestamp
                now,    // createdAt
                0       // avatarFrameType
        );

        mDb.collection(COLLECTION_USERS)
                .document(firebaseUser.getUid())
                .set(user)
                .addOnSuccessListener(unused -> cb.onSuccess(firebaseUser))
                .addOnFailureListener(e -> cb.onError("Profil nije mogao biti sačuvan. Pokušaj ponovo."));
    }

    // -------------------------------------------------------------------------
    // Prijava
    // -------------------------------------------------------------------------

    /**
     * Prijavljuje korisnika putem emaila ili korisničkog imena.
     *
     * <p>Ako {@code emailOrUsername} sadrži "@", tretira se kao email.
     * U suprotnom, email se traži u Firestore-u po korisničkom imenu.</p>
     *
     * <p>Nakon uspešne prijave, proverava se verifikacija emaila.
     * Ako email nije verifikovan, korisnik se odmah odjavljuje.</p>
     *
     * @param emailOrUsername email adresa ili korisničko ime
     * @param password        lozinka
     * @param cb              callback sa rezultatom operacije
     */
    public void login(@NonNull String emailOrUsername,
                      @NonNull String password,
                      @NonNull AuthCallback cb) {

        if (emailOrUsername.contains("@")) {
            // Direktna prijava putem emaila
            signInWithEmail(emailOrUsername, password, cb);
        } else {
            // Pronađi email po korisničkom imenu
            mDb.collection(COLLECTION_USERS)
                    .whereEqualTo("username", emailOrUsername)
                    .limit(1)
                    .get()
                    .addOnSuccessListener(querySnapshot -> {
                        if (querySnapshot.isEmpty()) {
                            cb.onError("Korisničko ime ne postoji.");
                            return;
                        }
                        QueryDocumentSnapshot doc =
                                (QueryDocumentSnapshot) querySnapshot.getDocuments().get(0);
                        String email = doc.getString("email");
                        if (email == null || email.isEmpty()) {
                            cb.onError("Greška pri učitavanju naloga. Pokušaj ponovo.");
                            return;
                        }
                        signInWithEmail(email, password, cb);
                    })
                    .addOnFailureListener(e ->
                            cb.onError("Greška pri pretrazi korisnika. Pokušaj ponovo."));
        }
    }

    /** Pomoćna metoda — prijava putem emaila i lozinke uz proveru verifikacije. */
    private void signInWithEmail(String email, String password, AuthCallback cb) {
        mAuth.signInWithEmailAndPassword(email, password)
                .addOnSuccessListener(authResult -> {
                    FirebaseUser user = authResult.getUser();
                    if (user == null) {
                        cb.onError("Greška pri prijavi. Pokušaj ponovo.");
                        return;
                    }
                    if (!user.isEmailVerified()) {
                        mAuth.signOut();
                        cb.onError("Mejl adresa nije verifikovana. Proveri svoju poštu i klikni na link za potvrdu.");
                        return;
                    }
                    cb.onSuccess(user);
                })
                .addOnFailureListener(e -> cb.onError(mapAuthError(e)));
    }

    // -------------------------------------------------------------------------
    // Promena lozinke
    // -------------------------------------------------------------------------

    /**
     * Menja lozinku trenutno ulogovanog korisnika.
     *
     * <p>Koristi reauthentikaciju pre promene lozinke (Firebase zahtev za
     * sigurnosno-osetljive operacije).</p>
     *
     * @param oldPassword stara lozinka (za reauthentikaciju)
     * @param newPassword nova lozinka
     * @param cb          callback sa rezultatom operacije
     */
    public void changePassword(@NonNull String oldPassword,
                               @NonNull String newPassword,
                               @NonNull AuthCallback cb) {

        FirebaseUser user = mAuth.getCurrentUser();
        if (user == null || user.getEmail() == null) {
            cb.onError("Nisi prijavljen.");
            return;
        }

        AuthCredential credential = EmailAuthProvider.getCredential(user.getEmail(), oldPassword);

        user.reauthenticate(credential)
                .addOnSuccessListener(unused ->
                        user.updatePassword(newPassword)
                                .addOnSuccessListener(v -> cb.onSuccess(user))
                                .addOnFailureListener(e -> cb.onError(mapAuthError(e))))
                .addOnFailureListener(e -> cb.onError("Trenutna lozinka je netačna."));
    }

    // -------------------------------------------------------------------------
    // Čitanje podataka korisnika
    // -------------------------------------------------------------------------

    /**
     * Učitava {@link User} profil trenutno ulogovanog korisnika iz Firestore-a.
     *
     * @param cb callback sa {@link User} objektom pri uspehu
     */
    public void getCurrentUserData(@NonNull UserCallback cb) {
        FirebaseUser firebaseUser = mAuth.getCurrentUser();
        if (firebaseUser == null) {
            cb.onError("Nisi prijavljen.");
            return;
        }

        mDb.collection(COLLECTION_USERS)
                .document(firebaseUser.getUid())
                .get()
                .addOnSuccessListener(documentSnapshot -> {
                    if (!documentSnapshot.exists()) {
                        cb.onError("Korisnički profil nije pronađen.");
                        return;
                    }
                    User user = documentSnapshot.toObject(User.class);
                    if (user == null) {
                        cb.onError("Greška pri čitanju korisničkog profila.");
                        return;
                    }
                    cb.onSuccess(user);
                })
                .addOnFailureListener(e ->
                        cb.onError("Greška pri učitavanju profila. Proveri internet vezu."));
    }

    // -------------------------------------------------------------------------
    // Odjava
    // -------------------------------------------------------------------------

    /**
     * Odjavljuje trenutno ulogovanog korisnika iz Firebase Auth.
     */
    public void logout() {
        mAuth.signOut();
    }

    // -------------------------------------------------------------------------
    // Pomoćne metode
    // -------------------------------------------------------------------------

    /**
     * Vraća {@link FirebaseUser} trenutno ulogovanog korisnika, ili {@code null}
     * ako niko nije prijavljen.
     *
     * @return trenutni Firebase korisnik ili null
     */
    @Nullable
    public FirebaseUser getCurrentFirebaseUser() {
        return mAuth.getCurrentUser();
    }

    /**
     * Proverava da li je korisnik prijavljen.
     *
     * @return true ako postoji aktivna sesija
     */
    public boolean isLoggedIn() {
        return mAuth.getCurrentUser() != null;
    }

    /**
     * Mapira Firebase Auth izuzetke na srpske poruke razumljive korisniku.
     *
     * @param e izuzetak koji je Firebase Auth bacio
     * @return poruka na srpskom jeziku
     */
    private String mapAuthError(@NonNull Exception e) {
        if (e instanceof FirebaseAuthWeakPasswordException) {
            return "Lozinka mora imati najmanje 6 karaktera.";
        } else if (e instanceof FirebaseAuthInvalidCredentialsException) {
            String msg = e.getMessage() != null ? e.getMessage() : "";
            if (msg.contains("password")) {
                return "Pogrešna lozinka.";
            } else if (msg.contains("email")) {
                return "Email adresa nije ispravnog formata.";
            }
            return "Pogrešni podaci za prijavu.";
        } else if (e instanceof FirebaseAuthUserCollisionException) {
            return "Nalog sa ovom email adresom već postoji.";
        } else if (e instanceof FirebaseAuthInvalidUserException) {
            String errorCode = ((FirebaseAuthInvalidUserException) e).getErrorCode();
            if ("ERROR_USER_NOT_FOUND".equals(errorCode)) {
                return "Nalog ne postoji.";
            } else if ("ERROR_USER_DISABLED".equals(errorCode)) {
                return "Nalog je onemogućen. Kontaktiraj podršku.";
            }
            return "Korisnički nalog nije pronađen.";
        }
        return "Došlo je do greške. Pokušaj ponovo.";
    }
}

package com.example.slagalica.logic.games;

import androidx.annotation.NonNull;

import java.text.Normalizer;
import java.util.regex.Pattern;

/**
 * Statička utility klasa sa poslovnom logikom za igru "Korak po korak".
 *
 * <p>Ne sme da instancira stanje — sve metode su {@code static}.
 * Ne importuje ništa iz {@code ui/} paketa.</p>
 */
public final class KorakPoKorakLogic {

    /** Regex koji uklanja Unicode kombinacijske oznake (dijakritike) nakon NFD normalizacije. */
    private static final Pattern COMBINING_MARKS = Pattern.compile("\\p{InCombiningDiacriticalMarks}+");

    /** Sprečava instanciranje utility klase. */
    private KorakPoKorakLogic() {
    }

    // -------------------------------------------------------------------------
    // Bodovanje
    // -------------------------------------------------------------------------

    /**
     * Vraća broj bodova koje igrač osvaja ako pogodi odgovor na datom koraku.
     *
     * <p>Formula: {@code 20 - 2 * korakIndex}, gde je {@code korakIndex} 0-baziran
     * (0 = prvi hint, najteži; 6 = sedmi hint, najlakši).</p>
     *
     * <table border="1">
     *   <tr><th>korakIndex</th><th>Bodovi</th></tr>
     *   <tr><td>0</td><td>20</td></tr>
     *   <tr><td>1</td><td>18</td></tr>
     *   <tr><td>2</td><td>16</td></tr>
     *   <tr><td>3</td><td>14</td></tr>
     *   <tr><td>4</td><td>12</td></tr>
     *   <tr><td>5</td><td>10</td></tr>
     *   <tr><td>6</td><td>8</td></tr>
     * </table>
     *
     * @param korakIndex 0-bazirani indeks koraka (hint-a) na kom je pogođen odgovor
     * @return broj bodova (8–20), ili 0 ako je indeks izvan opsega [0, 6]
     */
    public static int bodoviZaPogodakUKoraku(int korakIndex) {
        if (korakIndex < 0 || korakIndex > 6) {
            return 0;
        }
        return 20 - 2 * korakIndex;
    }

    /**
     * Vraća broj bodova koji se dodeljuju igraču kada protivnik pogodi
     * odgovor umesto njega (preuzimanje bodova).
     *
     * @return uvek 5 bodova
     */
    public static int bodoviZaPreuzimanje() {
        return 5;
    }

    // -------------------------------------------------------------------------
    // Provera odgovora
    // -------------------------------------------------------------------------

    /**
     * Proverava da li je korisnički odgovor tačan poređenjem sa rešenjem.
     *
     * <p>Poređenje je:
     * <ul>
     *   <li><b>case-insensitive</b> — "Jabuka" i "jabuka" su iste</li>
     *   <li><b>trim</b> — vodeći i završni razmaci se ignorišu</li>
     *   <li><b>diacritic-insensitive</b> — š→s, ž→z, đ→dj, č→c, ć→c;
     *       implementirano kroz Unicode NFD normalizaciju + uklanjanje
     *       combining diacritical marks</li>
     * </ul>
     * </p>
     *
     * <p>Primer: {@code tacanOdgovor("Šuma", "suma")} vraća {@code true}.</p>
     *
     * @param userAnswer odgovor koji je uneo korisnik (može biti null)
     * @param resenje    tačno rešenje iz Firestore dokumenta (može biti null)
     * @return {@code true} ako su odgovori ekvivalentni, {@code false} u suprotnom
     */
    public static boolean tacanOdgovor(String userAnswer, @NonNull String resenje) {
        if (userAnswer == null || userAnswer.trim().isEmpty()) {
            return false;
        }

        // Poseban slučaj: đ i Đ → "dj" jer NFD ne rastavlja đ na d + kombinacijski znak
        String normalizedUser    = normalizuj(userAnswer);
        String normalizedResenje = normalizuj(resenje);

        return normalizedUser.equalsIgnoreCase(normalizedResenje);
    }

    // -------------------------------------------------------------------------
    // Pomoćne metode
    // -------------------------------------------------------------------------

    /**
     * Normalizuje string za poređenje bez dijakritika:
     * <ol>
     *   <li>Trim-uje vodeće/završne razmake.</li>
     *   <li>Zamenjuje {@code đ}/{@code Đ} sa {@code dj}/{@code DJ} (NFD ih ne rastavlja).</li>
     *   <li>NFD normalizacija (rastavljanje znakova s dijakriticima na base + combining).</li>
     *   <li>Uklanjanje svih combining diacritical marks regex-om.</li>
     * </ol>
     *
     * @param s string za normalizaciju
     * @return normalizovani string, uvek malim slovima
     */
    private static String normalizuj(@NonNull String s) {
        String result = s.trim();

        // đ/Đ → dj (NFD ne rastavlja đ jer nije kompozit d+diakritik)
        result = result.replace('đ', 'd').replace('Đ', 'D');

        // NFD normalizacija: š → s + kombinacijski hačekov znak, itd.
        result = Normalizer.normalize(result, Normalizer.Form.NFD);

        // Ukloni sve combining diacritical marks (U+0300–U+036F)
        result = COMBINING_MARKS.matcher(result).replaceAll("");

        return result.toLowerCase();
    }
}

package com.example.slagalica.logic.games;

import androidx.annotation.NonNull;

import net.objecthunter.exp4j.Expression;
import net.objecthunter.exp4j.ExpressionBuilder;

import java.util.HashMap;
import java.util.Map;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

/**
 * Statička utility klasa sa poslovnom logikom za igru "Moj broj".
 *
 * <p>Ne sme da instancira stanje — sve metode su {@code static}.
 * Ne importuje ništa iz {@code ui/} paketa.</p>
 *
 * <p>Zavisnosti: exp4j 0.4.8 (deklarisan u {@code app/build.gradle}).</p>
 */
public final class MojBrojLogic {

    /** Regex koji izvlači sve celobrojne tokene iz izraza. */
    private static final Pattern BROJ_PATTERN = Pattern.compile("\\d+");

    /** Sprečava instanciranje utility klase. */
    private MojBrojLogic() {
    }

    // =========================================================================
    // Pomoćna klasa za rezultat evaluacije
    // =========================================================================

    /**
     * Nosi rezultat evaluacije matematičkog izraza.
     *
     * <ul>
     *   <li>Ako je {@code validan == true}: {@code rezultat} sadrži izračunatu vrednost.</li>
     *   <li>Ako je {@code validan == false}: {@code greska} opisuje razlog nevalidnosti.</li>
     * </ul>
     */
    public static class IzrazRezultat {
        /** True ako je izraz sintaksno ispravan, koristi dozvoljena pitanja i evaluacija uspešna. */
        public boolean validan;
        /** Izračunata vrednost izraza. Relevantno samo ako {@code validan == true}. */
        public double rezultat;
        /** Opis greške. Relevantno samo ako {@code validan == false}. */
        public String greska;

        /** Fabrikovna metoda za uspešan rezultat. */
        static IzrazRezultat ok(double rezultat) {
            IzrazRezultat r = new IzrazRezultat();
            r.validan  = true;
            r.rezultat = rezultat;
            return r;
        }

        /** Fabrikovna metoda za neuspešan rezultat. */
        static IzrazRezultat greska(String poruka) {
            IzrazRezultat r = new IzrazRezultat();
            r.validan = false;
            r.greska  = poruka;
            return r;
        }
    }

    // =========================================================================
    // Evaluacija izraza
    // =========================================================================

    /**
     * Evaluira matematički izraz unet od strane igrača.
     *
     * <p>Koraci:</p>
     * <ol>
     *   <li>Zamena UI simbola ({@code ×}→{@code *}, {@code ÷}→{@code /}).</li>
     *   <li>Sintaksna validacija (zagrade, operatori).</li>
     *   <li>Validacija multiset-a — svaki broj mora biti dostupan u tačnom broju pojavljivanja.</li>
     *   <li>Evaluacija putem exp4j.</li>
     * </ol>
     *
     * <p><b>Unit test primeri:</b></p>
     * <pre>
     *   evaluate("25+3",    [25,3,5,7,10,50])  → validan=true,  rezultat=28.0
     *   evaluate("3*3",     [25,3,5,7,10,50])  → validan=false, greska="Broj 3 nije dovoljno puta dostupan"
     *   evaluate("25/0",    [25,3,5,7,10,50])  → validan=false, greska="Deljenje nulom"
     *   evaluate("25++3",   [25,3,5,7,10,50])  → validan=false, greska="Dva uzastopna operatora"
     *   evaluate("(25+3",   [25,3,5,7,10,50])  → validan=false, greska="Nebalansirane zagrade"
     *   evaluate("",        [25,3,5,7,10,50])  → validan=false, greska="Izraz je prazan"
     * </pre>
     *
     * @param izraz           matematički izraz koji je uneo igrač (može sadržati × i ÷)
     * @param dostupniBrojevi niz od 6 dostupnih brojeva za ovu rundu
     * @return {@link IzrazRezultat} sa rezultatom ili opisom greške
     */
    @NonNull
    public static IzrazRezultat evaluate(@NonNull String izraz, @NonNull int[] dostupniBrojevi) {
        // Korak 1: normalizuj simbole
        String normalized = izraz.trim()
                .replace('×', '*')
                .replace('÷', '/');

        if (normalized.isEmpty()) {
            return IzrazRezultat.greska("Izraz je prazan.");
        }

        // Korak 2: sintaksna validacija
        IzrazRezultat sintaksaGreska = validirajSintaksu(normalized);
        if (sintaksaGreska != null) {
            return sintaksaGreska;
        }

        // Korak 3: validacija multiset-a
        IzrazRezultat multisetGreska = validirajMultiset(normalized, dostupniBrojevi);
        if (multisetGreska != null) {
            return multisetGreska;
        }

        // Korak 4: evaluacija putem exp4j
        try {
            Expression expression = new ExpressionBuilder(normalized).build();
            double rezultat = expression.evaluate();

            if (Double.isInfinite(rezultat) || Double.isNaN(rezultat)) {
                return IzrazRezultat.greska("Deljenje nulom nije dozvoljeno.");
            }

            return IzrazRezultat.ok(rezultat);

        } catch (ArithmeticException e) {
            return IzrazRezultat.greska("Deljenje nulom nije dozvoljeno.");
        } catch (Exception e) {
            return IzrazRezultat.greska("Izraz nije ispravan: " + e.getMessage());
        }
    }

    // =========================================================================
    // Bodovanje
    // =========================================================================

    /**
     * Izračunava bodove oba igrača za igru "Moj broj".
     *
     * <p>Pravila bodovanja:</p>
     * <ul>
     *   <li>Oba točna (jednaki traženom): svaki dobija 10 bodova.</li>
     *   <li>Samo jedan tačan: tačan dobija 10, drugi 0.</li>
     *   <li>Oba validni ali netačni, isti rezultat: igrač čija je runda dobija 5.</li>
     *   <li>Oba validni ali netačni, različiti: bliži traženom dobija 5.</li>
     *   <li>Nevalidan/prazan izraz: 0 bodova.</li>
     * </ul>
     *
     * <p><b>Unit test primeri:</b></p>
     * <pre>
     *   izracunajBodovanje(100, ok(100), ok(100), true)  → [10, 10]
     *   izracunajBodovanje(100, ok(100), ok(95),  true)  → [10, 0]
     *   izracunajBodovanje(100, ok(90),  ok(100), true)  → [0, 10]
     *   izracunajBodovanje(100, ok(95),  ok(90),  true)  → [5, 0]   // bliži
     *   izracunajBodovanje(100, ok(95),  ok(95),  true)  → [5, 0]   // isti, aktivan=r1
     *   izracunajBodovanje(100, greska,  greska,  true)  → [0, 0]
     * </pre>
     *
     * @param trazeni          traženi broj (cilj)
     * @param r1               rezultat prvog igrača
     * @param r2               rezultat drugog igrača
     * @param prviIgracJeAktivan true ako je runda "prvog igrača" (koristi se za rešavanje izjednačenja)
     * @return int[] dužine 2: {@code [bodoviPrvog, bodoviDrugog]}
     */
    @NonNull
    public static int[] izracunajBodovanje(double trazeni,
                                           @NonNull IzrazRezultat r1,
                                           @NonNull IzrazRezultat r2,
                                           boolean prviIgracJeAktivan) {
        boolean tacan1 = r1.validan && r1.rezultat == trazeni;
        boolean tacan2 = r2.validan && r2.rezultat == trazeni;

        // Oba tačna
        if (tacan1 && tacan2) {
            return new int[]{10, 10};
        }

        // Samo prvi tačan
        if (tacan1) {
            return new int[]{10, 0};
        }

        // Samo drugi tačan
        if (tacan2) {
            return new int[]{0, 10};
        }

        // Ni jedan nije tačan — daj 5 bliže ili aktiv igraču
        if (!r1.validan && !r2.validan) {
            return new int[]{0, 0};
        }

        if (!r1.validan) {
            // r2 je jedini validan, ali nije tačan → 5 njemu
            return new int[]{0, 5};
        }

        if (!r2.validan) {
            // r1 je jedini validan, ali nije tačan → 5 njemu
            return new int[]{5, 0};
        }

        // Oba validna ali netačna
        double razlika1 = Math.abs(r1.rezultat - trazeni);
        double razlika2 = Math.abs(r2.rezultat - trazeni);

        if (razlika1 < razlika2) {
            return new int[]{5, 0};
        } else if (razlika2 < razlika1) {
            return new int[]{0, 5};
        } else {
            // Isti rezultat ili ista udaljenost — aktivan igrač dobija 5
            return prviIgracJeAktivan ? new int[]{5, 0} : new int[]{0, 5};
        }
    }

    // =========================================================================
    // Pomoćne metode — validacija
    // =========================================================================

    /**
     * Proverava sintaksnu ispravnost izraza.
     *
     * @return {@link IzrazRezultat} sa greškom, ili {@code null} ako je sintaksa OK
     */
    private static IzrazRezultat validirajSintaksu(@NonNull String izraz) {
        // Provera balansiranosti zagrada
        int balance = 0;
        for (char c : izraz.toCharArray()) {
            if (c == '(') balance++;
            else if (c == ')') balance--;
            if (balance < 0) {
                return IzrazRezultat.greska("Nebalansirane zagrade.");
            }
        }
        if (balance != 0) {
            return IzrazRezultat.greska("Nebalansirane zagrade.");
        }

        // Ne sme počinjati sa operatorom (osim unarnog minus)
        if (izraz.matches("^[+*/].*")) {
            return IzrazRezultat.greska("Izraz ne sme počinjati sa operatorom.");
        }

        // Ne sme završavati se operatorom
        if (izraz.matches(".*[+\\-*/]$")) {
            return IzrazRezultat.greska("Izraz ne sme završavati se operatorom.");
        }

        // Nema dva uzastopna binarna operatora (npr. ++ ili */)
        if (izraz.matches(".*[+\\-*/]{2,}.*")) {
            // Dozvoli -- (dvostruki minus može biti unaran) i *- ili +- (unaran minus iza operatora)
            // Ali zabrani ++, **, //, /*, itd.
            if (izraz.matches(".*[+*/][+*/].*") || izraz.matches(".*[+*/]{2,}.*")) {
                return IzrazRezultat.greska("Dva uzastopna operatora nisu dozvoljena.");
            }
        }

        return null; // sintaksa OK
    }

    /**
     * Proverava da li svi brojevi u izrazu postoje u dostupnim brojevima (multiset provera).
     *
     * <p>Izvlači sve celobrojne tokene regex-om, pravi multiset od dostupnih brojeva,
     * i proverava da se svaki broj koristi najviše onoliko puta koliko se pojavljuje u
     * {@code dostupniBrojevi}.</p>
     *
     * @return {@link IzrazRezultat} sa greškom, ili {@code null} ako su svi brojevi dostupni
     */
    private static IzrazRezultat validirajMultiset(@NonNull String izraz,
                                                    @NonNull int[] dostupniBrojevi) {
        // Napravi multiset dostupnih
        Map<Integer, Integer> dostupniMap = new HashMap<>();
        for (int b : dostupniBrojevi) {
            dostupniMap.compute(b, (k, v) -> v == null ? 1 : v + 1);
        }

        // Izvuci sve brojeve iz izraza
        Matcher matcher = BROJ_PATTERN.matcher(izraz);
        Map<Integer, Integer> koriscenoMap = new HashMap<>();
        while (matcher.find()) {
            int broj = Integer.parseInt(matcher.group());
            koriscenoMap.compute(broj, (k, v) -> v == null ? 1 : v + 1);
        }

        // Proveri da svaki korišćeni broj postoji u dovoljnom broju
        for (Map.Entry<Integer, Integer> entry : koriscenoMap.entrySet()) {
            int broj      = entry.getKey();
            int koristeno = entry.getValue();
            Integer dostupnoBoxed = dostupniMap.get(broj);
            int dostupno = dostupnoBoxed != null ? dostupnoBoxed : 0;

            if (dostupno == 0) {
                return IzrazRezultat.greska("Broj " + broj + " nije u dostupnim brojevima.");
            }
            if (koristeno > dostupno) {
                return IzrazRezultat.greska("Broj " + broj + " nije dovoljno puta dostupan " +
                        "(dostupan " + dostupno + "×, korišćen " + koristeno + "×).");
            }
        }

        return null; // multiset OK
    }
}

package com.example.slagalica.ui.auth;

import android.content.Intent;
