     *
     * @return true ako su svi unosi ispravni, false u suprotnom
     */
    private boolean validateInputs(String email, String password) {
        boolean valid = true;

        if (email.isEmpty()) {
            tlEmail.setError(getString(R.string.error_field_required));
            valid = false;
        }

        if (password.isEmpty()) {
            tlPassword.setError(getString(R.string.error_field_required));
            valid = false;
        }

        return valid;
    }

    private void onForgotPasswordClicked() {
        startActivity(new Intent(this, ForgotPasswordActivity.class));
    }

    private void onRegisterClicked() {
        startActivity(new Intent(this, RegisterActivity.class));
    }
}

package com.example.slagalica.ui.auth;

import android.content.Intent;
import android.os.Bundle;
import android.view.View;
import android.widget.ProgressBar;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

import com.example.slagalica.R;
import com.example.slagalica.data.repository.UserRepository;
import com.example.slagalica.ui.main.MainActivity;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.snackbar.Snackbar;
import com.google.android.material.textfield.TextInputEditText;
import com.google.android.material.textfield.TextInputLayout;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.auth.FirebaseUser;

/**
 * Ekran za prijavu korisnika.
 * KT2: koristi {@link UserRepository} za Firebase autentifikaciju.
 * Podržava prijavu putem emaila ili korisničkog imena.
 */
public class LoginActivity extends AppCompatActivity {

    private TextInputLayout tlEmail;
    private TextInputLayout tlPassword;
    private TextInputEditText etEmail;
    private TextInputEditText etPassword;
    private MaterialButton btnLogin;
    private TextView tvForgotPassword;
    private TextView tvRegister;
    private ProgressBar pbLoading;

    private UserRepository userRepository;

    // -------------------------------------------------------------------------
    // Lifecycle
    // -------------------------------------------------------------------------

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        userRepository = UserRepository.getInstance();

        initViews();
        setupListeners();
    }

    @Override
    protected void onStart() {
        super.onStart();
        // Ako je korisnik već prijavljen i email je verifikovan, preskoči login ekran
        FirebaseUser current = FirebaseAuth.getInstance().getCurrentUser();
        if (current != null && current.isEmailVerified()) {
            goToMain();
        }
    }

    // -------------------------------------------------------------------------
    // Inicijalizacija
    // -------------------------------------------------------------------------

    private void initViews() {
        tlEmail        = findViewById(R.id.tlEmail);
        tlPassword     = findViewById(R.id.tlPassword);
        etEmail        = findViewById(R.id.etEmail);
        etPassword     = findViewById(R.id.etPassword);
        btnLogin       = findViewById(R.id.btnLogin);
        tvForgotPassword = findViewById(R.id.tvForgotPassword);
        tvRegister     = findViewById(R.id.tvRegister);
        pbLoading      = findViewById(R.id.pbLoading);
    }

    private void setupListeners() {
        btnLogin.setOnClickListener(v -> onLoginClicked());
        tvForgotPassword.setOnClickListener(v -> onForgotPasswordClicked());
        tvRegister.setOnClickListener(v -> onRegisterClicked());
    }

    // -------------------------------------------------------------------------
    // Akcije
    // -------------------------------------------------------------------------

    private void onLoginClicked() {
        tlEmail.setError(null);
        tlPassword.setError(null);

        String emailOrUsername = etEmail.getText() != null
                ? etEmail.getText().toString().trim() : "";
        String password = etPassword.getText() != null
                ? etPassword.getText().toString() : "";

        if (!validateInputs(emailOrUsername, password)) {
            return;
        }

        setLoading(true);

        userRepository.login(emailOrUsername, password, new UserRepository.AuthCallback() {
            @Override
            public void onSuccess(FirebaseUser user) {
                setLoading(false);
                goToMain();
            }

            @Override
            public void onError(String message) {
                setLoading(false);
                showError(message);
            }
        });
    }

    private void onForgotPasswordClicked() {
        startActivity(new Intent(this, ForgotPasswordActivity.class));
    }

    private void onRegisterClicked() {
        startActivity(new Intent(this, RegisterActivity.class));
    }

    // -------------------------------------------------------------------------
    // Validacija
    // -------------------------------------------------------------------------

    /**
     * Validira unesene podatke i postavlja greške na odgovarajuće TextInputLayout-ove.
     *
     * @return true ako su svi unosi ispravni, false u suprotnom
     */
    private boolean validateInputs(String emailOrUsername, String password) {
        boolean valid = true;

        if (emailOrUsername.isEmpty()) {
            tlEmail.setError(getString(R.string.error_field_required));
            valid = false;
        }

        if (password.isEmpty()) {
            tlPassword.setError(getString(R.string.error_field_required));
            valid = false;
        }

        return valid;
    }

    // -------------------------------------------------------------------------
    // Pomoćne metode
    // -------------------------------------------------------------------------

    /** Prikazuje ili skriva ProgressBar i onemogućava/omogućava dugme za prijavu. */
    private void setLoading(boolean isLoading) {
        pbLoading.setVisibility(isLoading ? View.VISIBLE : View.GONE);
        btnLogin.setEnabled(!isLoading);
    }

    /** Prikazuje Snackbar sa porukom greške. */
    private void showError(String message) {
        Snackbar.make(btnLogin, message, Snackbar.LENGTH_LONG).show();
    }

    /** Prelazi na MainActivity i zatvara back stack. */
    private void goToMain() {
        Intent intent = new Intent(this, MainActivity.class);
        intent.setFlags(Intent.FLAG_ACTIVITY_NEW_TASK | Intent.FLAG_ACTIVITY_CLEAR_TASK);
        startActivity(intent);
        finish();
    }
}

package com.example.slagalica.ui.auth;

import android.os.Bundle;
import android.widget.ArrayAdapter;
import android.widget.AutoCompleteTextView;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.slagalica.R;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.textfield.TextInputEditText;
import com.google.android.material.textfield.TextInputLayout;

import java.util.regex.Pattern;

/**
 * Ekran za registraciju novog korisnika.
 * KT1: samo GUI logika i validacija, bez Firebase poziva.
 */
public class RegisterActivity extends AppCompatActivity {

    /** Regex za validaciju email adrese. */
    private static final Pattern EMAIL_PATTERN =
            Pattern.compile("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$");

    /** Regex za korisničko ime: slova, cifre i donja crta, min 3 karaktera. */
    private static final Pattern USERNAME_PATTERN =
            Pattern.compile("^[A-Za-z0-9_]{3,}$");

    private TextInputLayout tlEmail;
    private TextInputLayout tlUsername;
    private TextInputLayout tlPassword;
    private TextInputLayout tlConfirmPassword;
    private TextInputLayout tlRegion;

    private TextInputEditText etEmail;
    private TextInputEditText etUsername;
    private TextInputEditText etPassword;
    private TextInputEditText etConfirmPassword;
    private AutoCompleteTextView actvRegion;

    private MaterialButton btnRegister;
    private TextView tvLogin;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_register);

        initViews();
        setupRegionDropdown();
        setupListeners();
    }

    private void initViews() {
        tlEmail = findViewById(R.id.tlEmail);
        tlUsername = findViewById(R.id.tlUsername);
        tlPassword = findViewById(R.id.tlPassword);
        tlConfirmPassword = findViewById(R.id.tlConfirmPassword);
        tlRegion = findViewById(R.id.tlRegion);

        etEmail = findViewById(R.id.etEmail);
        etUsername = findViewById(R.id.etUsername);
        etPassword = findViewById(R.id.etPassword);
        etConfirmPassword = findViewById(R.id.etConfirmPassword);
        actvRegion = findViewById(R.id.actvRegion);

        btnRegister = findViewById(R.id.btnRegister);
        tvLogin = findViewById(R.id.tvLogin);
    }

    private void setupRegionDropdown() {
        String[] regions = getResources().getStringArray(R.array.regions_array);
        ArrayAdapter<String> adapter = new ArrayAdapter<>(
                this,
                android.R.layout.simple_dropdown_item_1line,
                regions
        );
        actvRegion.setAdapter(adapter);
    }

    private void setupListeners() {
        btnRegister.setOnClickListener(v -> onRegisterClicked());
        tvLogin.setOnClickListener(v -> finish());
    }

    private void onRegisterClicked() {
        clearErrors();

        String email = getText(etEmail);
        String username = getText(etUsername);
        String password = getText(etPassword);
        String confirmPassword = getText(etConfirmPassword);
        String region = actvRegion.getText() != null ? actvRegion.getText().toString().trim() : "";

        if (!validateInputs(email, username, password, confirmPassword, region)) {
            return;
        }

        // KT1: mock registracija — Firebase se dodaje u KT2
        Toast.makeText(this, getString(R.string.register_success_mock), Toast.LENGTH_LONG).show();
        finish();
    }

    /**
     * Validira sva polja forme i postavlja odgovarajuće greške na TextInputLayout-ove.
     *
     * @return true ako su svi unosi ispravni, false ako postoji bar jedna greška
     */
    private boolean validateInputs(String email, String username,
                                   String password, String confirmPassword,
                                   String region) {
        boolean valid = true;

        if (email.isEmpty()) {
            tlEmail.setError(getString(R.string.error_field_required));
            valid = false;
        } else if (!EMAIL_PATTERN.matcher(email).matches()) {
            tlEmail.setError(getString(R.string.error_invalid_email));
            valid = false;
        }

        if (username.isEmpty()) {
            tlUsername.setError(getString(R.string.error_field_required));
            valid = false;
        } else if (username.length() < 3) {
            tlUsername.setError(getString(R.string.error_username_too_short));
            valid = false;
        } else if (!USERNAME_PATTERN.matcher(username).matches()) {
            tlUsername.setError(getString(R.string.error_username_invalid_chars));
            valid = false;
        }

        if (password.isEmpty()) {
            tlPassword.setError(getString(R.string.error_field_required));
            valid = false;
        } else if (password.length() < 6) {
            tlPassword.setError(getString(R.string.error_password_too_short));
            valid = false;
        }

        if (confirmPassword.isEmpty()) {
            tlConfirmPassword.setError(getString(R.string.error_field_required));
            valid = false;
        } else if (!confirmPassword.equals(password)) {
            tlConfirmPassword.setError(getString(R.string.error_passwords_do_not_match));
            valid = false;
        }

        if (region.isEmpty()) {
            tlRegion.setError(getString(R.string.error_region_not_selected));
            valid = false;
        }

        return valid;
    }

    /** Resetuje sve greške na svim TextInputLayout-ovima pre nove validacije. */
    private void clearErrors() {
        tlEmail.setError(null);
        tlUsername.setError(null);
        tlPassword.setError(null);
        tlConfirmPassword.setError(null);
        tlRegion.setError(null);
    }

    /**
     * Pomoćna metoda: čita i trim-uje tekst iz TextInputEditText.
     *
     * @param field polje iz koga se čita tekst
     * @return trimmovani tekst, ili prazan string ako je null
     */
    private String getText(TextInputEditText field) {
        return field.getText() != null ? field.getText().toString().trim() : "";
    }
}

package com.example.slagalica.ui.auth;

import android.os.Bundle;
import android.view.View;
import android.widget.ArrayAdapter;
import android.widget.AutoCompleteTextView;
import android.widget.ProgressBar;
import android.widget.TextView;

import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;

import com.example.slagalica.R;
import com.example.slagalica.data.repository.UserRepository;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.snackbar.Snackbar;
import com.google.android.material.textfield.TextInputEditText;
import com.google.android.material.textfield.TextInputLayout;
import com.google.firebase.auth.FirebaseUser;

import java.util.regex.Pattern;

/**
 * Ekran za registraciju novog korisnika.
 * KT2: koristi {@link UserRepository} za Firebase registraciju sa email verifikacijom.
 */
public class RegisterActivity extends AppCompatActivity {

    /** Regex za validaciju email adrese. */
    private static final Pattern EMAIL_PATTERN =
            Pattern.compile("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$");

    /** Regex za korisničko ime: slova, cifre i donja crta, min 3 karaktera. */
    private static final Pattern USERNAME_PATTERN =
            Pattern.compile("^[A-Za-z0-9_]{3,}$");

    private TextInputLayout tlEmail;
    private TextInputLayout tlUsername;
    private TextInputLayout tlPassword;
    private TextInputLayout tlConfirmPassword;
    private TextInputLayout tlRegion;

    private TextInputEditText etEmail;
    private TextInputEditText etUsername;
    private TextInputEditText etPassword;
    private TextInputEditText etConfirmPassword;
    private AutoCompleteTextView actvRegion;

    private MaterialButton btnRegister;
    private TextView tvLogin;
    private ProgressBar pbLoading;

    private UserRepository userRepository;

    // -------------------------------------------------------------------------
    // Lifecycle
    // -------------------------------------------------------------------------

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_register);

        userRepository = UserRepository.getInstance();

        initViews();
        setupRegionDropdown();
        setupListeners();
    }

    // -------------------------------------------------------------------------
    // Inicijalizacija
    // -------------------------------------------------------------------------

    private void initViews() {
        tlEmail           = findViewById(R.id.tlEmail);
        tlUsername        = findViewById(R.id.tlUsername);
        tlPassword        = findViewById(R.id.tlPassword);
        tlConfirmPassword = findViewById(R.id.tlConfirmPassword);
        tlRegion          = findViewById(R.id.tlRegion);

        etEmail           = findViewById(R.id.etEmail);
        etUsername        = findViewById(R.id.etUsername);
        etPassword        = findViewById(R.id.etPassword);
        etConfirmPassword = findViewById(R.id.etConfirmPassword);
        actvRegion        = findViewById(R.id.actvRegion);

        btnRegister = findViewById(R.id.btnRegister);
        tvLogin     = findViewById(R.id.tvLogin);
        pbLoading   = findViewById(R.id.pbLoading);
    }

    private void setupRegionDropdown() {
        String[] regions = getResources().getStringArray(R.array.regions_array);
        ArrayAdapter<String> adapter = new ArrayAdapter<>(
                this,
                android.R.layout.simple_dropdown_item_1line,
                regions
        );
        actvRegion.setAdapter(adapter);
    }

    private void setupListeners() {
        btnRegister.setOnClickListener(v -> onRegisterClicked());
        tvLogin.setOnClickListener(v -> finish());
    }

    // -------------------------------------------------------------------------
    // Registracija
    // -------------------------------------------------------------------------

    private void onRegisterClicked() {
        clearErrors();

        String email           = getText(etEmail);
        String username        = getText(etUsername);
        String password        = getText(etPassword);
        String confirmPassword = getText(etConfirmPassword);
        String region          = actvRegion.getText() != null
                ? actvRegion.getText().toString().trim() : "";

        if (!validateInputs(email, username, password, confirmPassword, region)) {
            return;
        }

        setLoading(true);

        userRepository.register(email, username, region, password,
                new UserRepository.AuthCallback() {
                    @Override
                    public void onSuccess(FirebaseUser user) {
                        setLoading(false);
                        showVerificationDialog();
                    }

                    @Override
                    public void onError(String message) {
                        setLoading(false);
                        showError(message);
                    }
                });
    }

    // -------------------------------------------------------------------------
    // Dijalozi i feedback
    // -------------------------------------------------------------------------

    /**
     * Prikazuje AlertDialog koji obaveštava korisnika da proveri mejl.
     * Klik na OK zatvara RegisterActivity i vraća na LoginActivity.
     */
    private void showVerificationDialog() {
        new AlertDialog.Builder(this)
                .setTitle(getString(R.string.register_dialog_verify_title))
                .setMessage(getString(R.string.register_dialog_verify_message))
                .setCancelable(false)
                .setPositiveButton(getString(R.string.register_dialog_verify_ok),
                        (dialog, which) -> finish())
                .show();
    }

    /** Prikazuje Snackbar sa porukom greške. */
    private void showError(String message) {
        Snackbar.make(btnRegister, message, Snackbar.LENGTH_LONG).show();
    }

    /** Prikazuje ili skriva ProgressBar i onemogućava/omogućava dugme. */
    private void setLoading(boolean isLoading) {
        pbLoading.setVisibility(isLoading ? View.VISIBLE : View.GONE);
        btnRegister.setEnabled(!isLoading);
    }

    // -------------------------------------------------------------------------
    // Validacija
    // -------------------------------------------------------------------------

    /**
     * Validira sva polja forme i postavlja odgovarajuće greške na TextInputLayout-ove.
     * Proverava sva polja odjednom — korisnik vidi sve greške istovremeno.
     *
     * @return true ako su svi unosi ispravni, false ako postoji bar jedna greška
     */
    private boolean validateInputs(String email, String username,
                                   String password, String confirmPassword,
                                   String region) {
        boolean valid = true;

        if (email.isEmpty()) {
            tlEmail.setError(getString(R.string.error_field_required));
            valid = false;
        } else if (!EMAIL_PATTERN.matcher(email).matches()) {
            tlEmail.setError(getString(R.string.error_invalid_email));
            valid = false;
        }

        if (username.isEmpty()) {
            tlUsername.setError(getString(R.string.error_field_required));
            valid = false;
        } else if (username.length() < 3) {
            tlUsername.setError(getString(R.string.error_username_too_short));
            valid = false;
        } else if (!USERNAME_PATTERN.matcher(username).matches()) {
            tlUsername.setError(getString(R.string.error_username_invalid_chars));
            valid = false;
        }

        if (password.isEmpty()) {
            tlPassword.setError(getString(R.string.error_field_required));
            valid = false;
        } else if (password.length() < 6) {
            tlPassword.setError(getString(R.string.error_password_too_short));
            valid = false;
        }

        if (confirmPassword.isEmpty()) {
            tlConfirmPassword.setError(getString(R.string.error_field_required));
            valid = false;
        } else if (!confirmPassword.equals(password)) {
            tlConfirmPassword.setError(getString(R.string.error_passwords_do_not_match));
            valid = false;
        }

        if (region.isEmpty()) {
            tlRegion.setError(getString(R.string.error_region_not_selected));
            valid = false;
        }

        return valid;
    }

    /** Resetuje sve greške na svim TextInputLayout-ovima pre nove validacije. */
    private void clearErrors() {
        tlEmail.setError(null);
        tlUsername.setError(null);
        tlPassword.setError(null);
        tlConfirmPassword.setError(null);
        tlRegion.setError(null);
    }

    /**
     * Pomoćna metoda: čita i trim-uje tekst iz TextInputEditText.
     *
     * @param field polje iz koga se čita tekst
     * @return trimmovani tekst, ili prazan string ako je null
     */
    private String getText(TextInputEditText field) {
        return field.getText() != null ? field.getText().toString().trim() : "";
    }
}

package com.example.slagalica.ui.games;

import android.os.Bundle;
import android.os.CountDownTimer;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.slagalica.R;
import com.example.slagalica.data.model.Korak;
import com.example.slagalica.data.model.KorakState;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.textfield.TextInputEditText;
import com.google.android.material.textfield.TextInputLayout;

import java.util.ArrayList;
import java.util.List;

/**
 * Aktivnost za igru "Korak po korak".
 * KT1: vizuelni demo — svaki 10s se otvara sledeći hint, bez prave validacije.
 * KT2: biće nadograđena Firebase integracijom i tačnom proverom odgovora.
 */
public class KorakPoKorakActivity extends AppCompatActivity {

    // KT1: fake hint-ovi na temu "JABUKA"
    private static final String[] FAKE_HINTS = {
            "voće",
            "crvena ili zelena",
            "Newton",
            "raste na drvetu",
            "Adam i Eva",
            "u tortama i pitama",
            "JA_UKA"
    };

    private RecyclerView rvKoraci;
    private TextInputLayout tlGuess;
    private TextInputEditText etGuess;
    private MaterialButton btnGuess;
    private MaterialButton btnGiveUp;

    private KorakAdapter adapter;

    /** Tajmer za otvaranje hint-ova — čuva se kao polje i cancels se u onDestroy(). */
    private CountDownTimer hintTimer;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_korak_po_korak);

        initViews();
        setupRecyclerView();
        setupListeners();
        startHintTimer();
    }

    private void initViews() {
        rvKoraci = findViewById(R.id.rvKoraci);
        tlGuess  = findViewById(R.id.tlGuess);
        etGuess  = findViewById(R.id.etGuess);
        btnGuess  = findViewById(R.id.btnGuess);
        btnGiveUp = findViewById(R.id.btnGiveUp);
    }

    private void setupRecyclerView() {
        List<Korak> koraci = buildFakeKoraci();
        adapter = new KorakAdapter(koraci);
        rvKoraci.setLayoutManager(new LinearLayoutManager(this));
        rvKoraci.setAdapter(adapter);
    }

    /** Gradi listu od 7 zaključanih koraka s fake hint-ovima. */
    private List<Korak> buildFakeKoraci() {
        List<Korak> list = new ArrayList<>();
        for (int i = 0; i < FAKE_HINTS.length; i++) {
            list.add(new Korak(i + 1, FAKE_HINTS[i], KorakState.ZAKLJUCAN));
        }
        return list;
    }

    private void setupListeners() {
        btnGuess.setOnClickListener(v ->
                Toast.makeText(this, "(KT1) Provera odgovora", Toast.LENGTH_SHORT).show());

        btnGiveUp.setOnClickListener(v -> finish());
    }

    /**
     * Pokreće CountDownTimer od 70s koji svaki 10s otvara sledeći hint.
     * Na isteku prikazuje Toast poruku.
     */
    private void startHintTimer() {
        hintTimer = new CountDownTimer(70_000, 10_000) {

            @Override
            public void onTick(long millisUntilFinished) {
                adapter.otvoriSledeci();
            }

            @Override
            public void onFinish() {
                Toast.makeText(KorakPoKorakActivity.this,
                        getString(R.string.korak_time_up),
                        Toast.LENGTH_SHORT).show();
            }
        }.start();
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (hintTimer != null) {
            hintTimer.cancel();
        }
    }
}

package com.example.slagalica.ui.games;

import android.os.Bundle;
import android.os.CountDownTimer;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;

import com.example.slagalica.R;
import com.example.slagalica.data.model.Korak;
import com.example.slagalica.data.model.KorakState;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.textfield.TextInputEditText;
import com.google.android.material.textfield.TextInputLayout;

import java.util.ArrayList;
import java.util.List;

/**
 * Aktivnost za igru "Korak po korak".
 * KT1: vizuelni demo — svaki 10s se otvara sledeći hint, bez prave validacije.
 * KT2: biće nadograđena Firebase integracijom i tačnom proverom odgovora.
 */
public class KorakPoKorakActivity extends AppCompatActivity {

    // KT1: fake hint-ovi na temu "JABUKA"
    private static final String[] FAKE_HINTS = {
            "voće",
            "crvena ili zelena",
            "Newton",
            "raste na drvetu",
            "Adam i Eva",
            "u tortama i pitama",
            "JA_UKA"
    };

    private RecyclerView rvKoraci;
    private TextInputLayout tlGuess;
    private TextInputEditText etGuess;
    private MaterialButton btnGuess;
    private MaterialButton btnGiveUp;

    private KorakAdapter adapter;

    /** Tajmer za otvaranje hint-ova — čuva se kao polje i cancels se u onDestroy(). */
    private CountDownTimer hintTimer;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_korak_po_korak);

        initViews();
        setupRecyclerView();
        setupListeners();
        startHintTimer();
    }

    private void initViews() {
        rvKoraci = findViewById(R.id.rvKoraci);
        tlGuess  = findViewById(R.id.tlGuess);
        etGuess  = findViewById(R.id.etGuess);
        btnGuess  = findViewById(R.id.btnGuess);
        btnGiveUp = findViewById(R.id.btnGiveUp);
    }

    private void setupRecyclerView() {
        List<Korak> koraci = buildFakeKoraci();
        adapter = new KorakAdapter(koraci);
        rvKoraci.setLayoutManager(new LinearLayoutManager(this));
        rvKoraci.setAdapter(adapter);
        // Otvori prvi hint odmah — preostalih 6 otvara tajmer (svakih 10s)
        adapter.otvoriSledeci();
    }

    /** Gradi listu od 7 zaključanih koraka s fake hint-ovima. */
    private List<Korak> buildFakeKoraci() {
        List<Korak> list = new ArrayList<>();
        for (int i = 0; i < FAKE_HINTS.length; i++) {
            list.add(new Korak(i + 1, FAKE_HINTS[i], KorakState.ZAKLJUCAN));
        }
        return list;
    }

    private void setupListeners() {
        btnGuess.setOnClickListener(v ->
                Toast.makeText(this, "(KT1) Provera odgovora", Toast.LENGTH_SHORT).show());

        btnGiveUp.setOnClickListener(v -> finish());
    }

    /**
     * Pokreće CountDownTimer od 70s koji svaki 10s otvara sledeći hint.
     * Na isteku prikazuje Toast poruku.
     */
    private void startHintTimer() {
        hintTimer = new CountDownTimer(70_000, 10_000) {

            @Override
            public void onTick(long millisUntilFinished) {
                adapter.otvoriSledeci();
            }

            @Override
            public void onFinish() {
                Toast.makeText(KorakPoKorakActivity.this,
                        getString(R.string.korak_time_up),
                        Toast.LENGTH_SHORT).show();
            }
        }.start();
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (hintTimer != null) {
            hintTimer.cancel();
        }
    }
}

package com.example.slagalica.ui.games;

import android.os.Bundle;
import android.os.CountDownTimer;
import android.widget.ProgressBar;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.example.slagalica.R;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.textfield.TextInputEditText;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Random;

/**
 * Aktivnost za igru "Moj broj".
 * KT1: UI radi, logika je mock — nema exp4j validacije ni shake senzora.
 * KT2: prova validacija izraza (multiset + exp4j), shake-to-stop, bodovanje.
 *
 * Faze igre:
 * 0 — čeka prvi STOP (generiše traženi broj)
 * 1 — čeka drugi STOP (generiše 6 dostupnih brojeva, pokreće tajmer)
 * 2 — aktivna igra (unos izraza je moguć)
 */
public class MojBrojActivity extends AppCompatActivity {

    private static final int TIMER_DURATION_MS = 60_000;
    private static final int TIMER_TICK_MS     = 1_000;

    // Views
    private TextView   tvTrazeniBroj;
    private TextView[] tvBrojevi;          // tvBroj1..tvBroj6
    private TextInputEditText etIzraz;
    private ProgressBar pbTimer;

    // Tastatura — brojčana dugmad za dostupne brojeve
    private MaterialButton[] btnBrojevi;   // btnB1..btnB6

    // Stanje
    private StringBuilder izraz = new StringBuilder();
    private int faza = 0;
    private CountDownTimer gameTimer;
    private final Random random = new Random();

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_moj_broj);

        initViews();
        setupListeners();
    }

    // =========================================================================
    // Inicijalizacija
    // =========================================================================

    private void initViews() {
        tvTrazeniBroj = findViewById(R.id.tvTrazeniBroj);
        pbTimer       = findViewById(R.id.pbTimer);
        etIzraz       = findViewById(R.id.etIzraz);

        tvBrojevi = new TextView[]{
                findViewById(R.id.tvBroj1),
                findViewById(R.id.tvBroj2),
                findViewById(R.id.tvBroj3),
                findViewById(R.id.tvBroj4),
                findViewById(R.id.tvBroj5),
                findViewById(R.id.tvBroj6)
        };

        btnBrojevi = new MaterialButton[]{
                findViewById(R.id.btnB1),
                findViewById(R.id.btnB2),
                findViewById(R.id.btnB3),
                findViewById(R.id.btnB4),
                findViewById(R.id.btnB5),
                findViewById(R.id.btnB6)
        };
    }

    private void setupListeners() {
        // Brojčana dugmad — dodaju vrednost broja u izraz (samo u fazi 2)
        for (int i = 0; i < btnBrojevi.length; i++) {
            final int idx = i;
            btnBrojevi[i].setOnClickListener(v -> {
                if (faza == 2) {
                    appendToIzraz(tvBrojevi[idx].getText().toString());
                }
            });
        }

        // Operatori
        findViewById(R.id.btnPlus).setOnClickListener(v       -> appendToIzraz("+"));
        findViewById(R.id.btnMinus).setOnClickListener(v      -> appendToIzraz("-"));
        findViewById(R.id.btnMult).setOnClickListener(v       -> appendToIzraz("×"));
        findViewById(R.id.btnDiv).setOnClickListener(v        -> appendToIzraz("÷"));
        findViewById(R.id.btnLeftParen).setOnClickListener(v  -> appendToIzraz("("));
        findViewById(R.id.btnRightParen).setOnClickListener(v -> appendToIzraz(")"));

        // Brisanje i reset
        findViewById(R.id.btnBackspace).setOnClickListener(v -> {
            if (izraz.length() > 0) {
                izraz.deleteCharAt(izraz.length() - 1);
                osvežiIzraz();
            }
        });
        findViewById(R.id.btnClear).setOnClickListener(v -> {
            izraz.setLength(0);
            osvežiIzraz();
        });

        // STOP — dvofazni
        findViewById(R.id.btnStop).setOnClickListener(v -> onStopClicked());

        // Potvrdi
        findViewById(R.id.btnPotvrdi).setOnClickListener(v ->
                Toast.makeText(this, getString(R.string.moj_broj_toast_kt1_validate),
                        Toast.LENGTH_SHORT).show());

        // Predaj
        findViewById(R.id.btnGiveUp).setOnClickListener(v -> finish());
    }

    // =========================================================================
    // Logika faza
    // =========================================================================

    private void onStopClicked() {
        if (faza == 0) {
            // Faza 0 → generiši traženi broj
            int cilj = 100 + random.nextInt(900);   // [100, 999]
            tvTrazeniBroj.setText(String.valueOf(cilj));
            faza = 1;

        } else if (faza == 1) {
            // Faza 1 → generiši 6 dostupnih brojeva i pokreni tajmer
            int[] brojevi = generisi6Brojeva();
            prikaziBrojeve(brojevi);
            pokreniTimer60s();
            faza = 2;
        }
        // faza == 2: STOP pokrenut tokom igre → ignorisati ili tretirati kao predaju (KT2)
    }

    // =========================================================================
    // Generisanje brojeva
    // =========================================================================

    /**
     * Generiše skup od 6 dostupnih brojeva:
     * <ul>
     *   <li>4 jednocifrena (1–9)</li>
     *   <li>1 iz skupa {10, 15, 20}</li>
     *   <li>1 iz skupa {25, 50, 75, 100}</li>
     * </ul>
     * Rezultat je izmešan slučajnim redosledom.
     *
     * @return niz od 6 celih brojeva
     */
    private int[] generisi6Brojeva() {
        int[] mali    = {10, 15, 20};
        int[] veliki  = {25, 50, 75, 100};

        List<Integer> lista = new ArrayList<>();

        // 4 jednocifrena (1–9, ponavljanje dozvoljeno)
        for (int i = 0; i < 4; i++) {
            lista.add(1 + random.nextInt(9));
        }

        // 1 iz {10, 15, 20}
        lista.add(mali[random.nextInt(mali.length)]);

        // 1 iz {25, 50, 75, 100}
        lista.add(veliki[random.nextInt(veliki.length)]);

        Collections.shuffle(lista, random);

        int[] rezultat = new int[lista.size()];
        for (int i = 0; i < lista.size(); i++) {
            rezultat[i] = lista.get(i);
        }
        return rezultat;
    }

    /** Puni tvBroj1..tvBroj6 i btnB1..btnB6 sa generisanim brojevima. */
    private void prikaziBrojeve(int[] brojevi) {
        for (int i = 0; i < tvBrojevi.length; i++) {
            String vrednost = String.valueOf(brojevi[i]);
            tvBrojevi[i].setText(vrednost);
            btnBrojevi[i].setText(vrednost);
        }
    }

    // =========================================================================
    // Tajmer
    // =========================================================================

    /**
     * Pokreće CountDownTimer od 60s, ažurira ProgressBar svaki 1s.
     * Na isteku prikazuje Toast i završava igru.
     */
    private void pokreniTimer60s() {
        gameTimer = new CountDownTimer(TIMER_DURATION_MS, TIMER_TICK_MS) {

            @Override
            public void onTick(long millisUntilFinished) {
                int sekundePreostale = (int) (millisUntilFinished / 1000);
                pbTimer.setProgress(sekundePreostale);
            }

            @Override
            public void onFinish() {
                pbTimer.setProgress(0);
                Toast.makeText(MojBrojActivity.this,
                        getString(R.string.moj_broj_time_up),
                        Toast.LENGTH_SHORT).show();
            }
        }.start();
    }

    // =========================================================================
    // Pomoćne metode
    // =========================================================================

    /** Dodaje token na kraj izgradnje izraza i osvežava polje za prikaz. */
    private void appendToIzraz(String token) {
        izraz.append(token);
        osvežiIzraz();
    }

    /** Sinhronizuje TextInputEditText sa sadržajem StringBuilder-a. */
    private void osvežiIzraz() {
        etIzraz.setText(izraz.toString());
    }

    // =========================================================================
    // Lifecycle
    // =========================================================================

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (gameTimer != null) {
            gameTimer.cancel();
        }
    }
}

package com.example.slagalica.ui.games;

import android.content.Intent;
import android.os.Bundle;
import android.os.CountDownTimer;
import android.widget.ProgressBar;
import android.widget.TextView;

import androidx.appcompat.app.AlertDialog;
import androidx.appcompat.app.AppCompatActivity;

import com.example.slagalica.R;
import com.example.slagalica.logic.games.MojBrojLogic;
import com.example.slagalica.util.ShakeDetector;
import com.google.android.material.button.MaterialButton;
import com.google.android.material.snackbar.Snackbar;
import com.google.android.material.textfield.TextInputEditText;
import com.google.android.material.textfield.TextInputLayout;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Random;

/**
 * Aktivnost za igru "Moj broj".
 * KT2: puna implementacija — shake-to-stop, exp4j validacija izraza, bodovanje.
 *
 * <p>Faze igre:
 * <ul>
 *   <li>0 — čeka prvi STOP (ili auto-timer 5s) → generiše traženi broj.</li>
 *   <li>1 — čeka drugi STOP (ili auto-timer 5s) → generiše 6 dostupnih brojeva + pokreće 60s timer.</li>
 *   <li>2 — aktivna igra: igrač unosi izraz, pritiska Potvrdi ili protekne 60s.</li>
 * </ul>
 * </p>
 */
public class MojBrojActivity extends AppCompatActivity {

    /** Ključ za Intent extra koji prenosi bodove nazad u MatchOrchestratorActivity. */
    public static final String EXTRA_BODOVI = "moj_broj_bodovi";

    private static final int ROUND_DURATION_MS = 60_000;
    private static final int ROUND_TICK_MS     = 1_000;
    private static final int AUTO_STOP_MS      = 5_000;   // auto-STOP ako igrač ne pritisne
    private static final int MAX_ROUNDS        = 2;

    // ─── Views ───────────────────────────────────────────────────────────────
    private TextView          tvTrazeniBroj;
    private TextView[]        tvBrojevi;
    private TextInputLayout   tlIzraz;
    private TextInputEditText etIzraz;
    private ProgressBar       pbTimer;
    private TextView          tvRound;
    private TextView          tvScore;
    private MaterialButton[]  btnBrojevi;

    // ─── Stanje igre ─────────────────────────────────────────────────────────
    private ShakeDetector    shakeDetector;
    private CountDownTimer   rundaTimer;
    private CountDownTimer   autoStopTimer;

    private final StringBuilder izraz        = new StringBuilder();
    private int[]               dostupniBrojevi;
    private int                 trazeniBroj;
    private int                 faza         = 0;
    private int                 trenutnaRunda = 1;
    private int                 ukupnoBodova  = 0;

    private final Random random = new Random();

    // =========================================================================
    // Lifecycle
    // =========================================================================

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_moj_broj);

        initViews();
        setupListeners();

        shakeDetector = new ShakeDetector(this, this::onStopClicked);
        pokreniRundu();
    }

    @Override
    protected void onResume() {
        super.onResume();
        shakeDetector.start();
    }

    @Override
    protected void onPause() {
        super.onPause();
        shakeDetector.stop();
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        otkaziTimere();
    }

    // =========================================================================
    // Inicijalizacija
    // =========================================================================

    private void initViews() {
        tvTrazeniBroj = findViewById(R.id.tvTrazeniBroj);
        pbTimer       = findViewById(R.id.pbTimer);
        tlIzraz       = findViewById(R.id.tlIzraz);
        etIzraz       = findViewById(R.id.etIzraz);
        tvRound       = findViewById(R.id.tvRound);
        tvScore       = findViewById(R.id.tvScore);

        tvBrojevi = new TextView[]{
                findViewById(R.id.tvBroj1), findViewById(R.id.tvBroj2),
                findViewById(R.id.tvBroj3), findViewById(R.id.tvBroj4),
                findViewById(R.id.tvBroj5), findViewById(R.id.tvBroj6)
        };

        btnBrojevi = new MaterialButton[]{
                findViewById(R.id.btnB1), findViewById(R.id.btnB2),
                findViewById(R.id.btnB3), findViewById(R.id.btnB4),
                findViewById(R.id.btnB5), findViewById(R.id.btnB6)
        };
    }

    private void setupListeners() {
        // Brojčana dugmad — samo u fazi 2
        for (int i = 0; i < btnBrojevi.length; i++) {
            final int idx = i;
            btnBrojevi[i].setOnClickListener(v -> {
                if (faza == 2) appendToIzraz(tvBrojevi[idx].getText().toString());
            });
        }

        // Operatori
        findViewById(R.id.btnPlus).setOnClickListener(v       -> appendToIzraz("+"));
        findViewById(R.id.btnMinus).setOnClickListener(v      -> appendToIzraz("-"));
        findViewById(R.id.btnMult).setOnClickListener(v       -> appendToIzraz("×"));
        findViewById(R.id.btnDiv).setOnClickListener(v        -> appendToIzraz("÷"));
        findViewById(R.id.btnLeftParen).setOnClickListener(v  -> appendToIzraz("("));
        findViewById(R.id.btnRightParen).setOnClickListener(v -> appendToIzraz(")"));

        // Brisanje i reset
        findViewById(R.id.btnBackspace).setOnClickListener(v -> {
            if (izraz.length() > 0) {
                izraz.deleteCharAt(izraz.length() - 1);
                osvežiIzraz();
            }
        });
        findViewById(R.id.btnClear).setOnClickListener(v -> {
            izraz.setLength(0);
            osvežiIzraz();
        });

        // STOP (dugme) i Potvrdi
        findViewById(R.id.btnStop).setOnClickListener(v   -> onStopClicked());
        findViewById(R.id.btnPotvrdi).setOnClickListener(v -> naPotvrdi());

        // Predaj
        findViewById(R.id.btnGiveUp).setOnClickListener(v -> showGiveUpDialog());
    }

    // =========================================================================
    // Tok runde
    // =========================================================================

    /** Resetuje UI i pokreće novu rundu od faze 0. */
    private void pokreniRundu() {
        faza = 0;
        izraz.setLength(0);
        osvežiIzraz();
        tlIzraz.setError(null);

        // Resetuj prikaz
        tvTrazeniBroj.setText(getString(R.string.moj_broj_target_default));
        for (int i = 0; i < tvBrojevi.length; i++) {
            tvBrojevi[i].setText(getString(R.string.moj_broj_number_default));
            btnBrojevi[i].setText(getString(R.string.moj_broj_number_default));
        }
        pbTimer.setProgress(60);
        azurirajHeader();

        // Auto-timer: ako igrač ne pritisne STOP za 5s, skripta to uradi sama
        pokreniAutoStop();
    }

    /**
     * Pokreće 5s auto-timer koji automatski izvršava STOP akciju
     * (koristi se i za fazu 0 i za fazu 1).
     */
    private void pokreniAutoStop() {
        otkaziAutoStop();
        autoStopTimer = new CountDownTimer(AUTO_STOP_MS, AUTO_STOP_MS) {
            @Override public void onTick(long ms) { }
            @Override public void onFinish() { onStopClicked(); }
        }.start();
    }

    // =========================================================================
    // STOP logika (klik dugmeta + shake + auto-timer)
    // =========================================================================

    private void onStopClicked() {
        otkaziAutoStop();

        if (faza == 0) {
            // Generiši traženi broj [100, 999]
            trazeniBroj = 100 + random.nextInt(900);
            tvTrazeniBroj.setText(String.valueOf(trazeniBroj));
            faza = 1;
            pokreniAutoStop();  // čekaj STOP za dostupne brojeve

        } else if (faza == 1) {
            // Generiši 6 dostupnih brojeva i pokreni 60s igru
            dostupniBrojevi = generisi6Brojeva();
            prikaziBrojeve(dostupniBrojevi);
            faza = 2;
            pokreniTimer60s();

        } else if (faza == 2) {
            // Shake tokom igre = predaja runde bez bodova
            onRundaZavrsena(null);
        }
    }

    // =========================================================================
    // Potvrdi (evaluacija izraza)
    // =========================================================================

    private void naPotvrdi() {
        if (faza != 2) return;

        String unosStr = etIzraz.getText() != null ? etIzraz.getText().toString() : "";
        if (unosStr.trim().isEmpty()) {
            tlIzraz.setError(getString(R.string.error_field_required));
            return;
        }
        tlIzraz.setError(null);

        MojBrojLogic.IzrazRezultat rezultat = MojBrojLogic.evaluate(unosStr, dostupniBrojevi);

        if (!rezultat.validan) {
            tlIzraz.setError(rezultat.greska);
            return;
        }

        // Zaokruži na int za poređenje
        int izracunato = (int) Math.round(rezultat.rezultat);

        if (izracunato == trazeniBroj) {
            // Tačan odgovor
            otkaziTimere();
            ukupnoBodova += 10;
            azurirajScore();
            onRundaZavrsena(rezultat);
        } else {
            // Nije tačno — prikaži rezultat, nastavi igru
            Snackbar.make(etIzraz,
                    getString(R.string.moj_broj_dialog_near_msg, izracunato, trazeniBroj),
                    Snackbar.LENGTH_SHORT).show();
        }
    }

    // =========================================================================
    // Tajmer 60s
    // =========================================================================

    private void pokreniTimer60s() {
        otkaziRunduTimer();
        rundaTimer = new CountDownTimer(ROUND_DURATION_MS, ROUND_TICK_MS) {
            @Override
            public void onTick(long ms) {
                pbTimer.setProgress((int) (ms / 1000));
            }

            @Override
            public void onFinish() {
                pbTimer.setProgress(0);
                onRundaIstekla();
            }
        }.start();
    }

    // =========================================================================
    // Kraj runde
    // =========================================================================

    /** Poziva se kada tajmer istekne bez tačnog odgovora. */
    private void onRundaIstekla() {
        faza = 0;
        boolean jePoslednja = (trenutnaRunda >= MAX_ROUNDS);

        new AlertDialog.Builder(this)
                .setTitle(getString(R.string.moj_broj_dialog_timeout_title))
                .setMessage(getString(R.string.moj_broj_dialog_timeout_msg, trazeniBroj))
                .setCancelable(false)
                .setPositiveButton(
                        jePoslednja ? getString(R.string.moj_broj_dialog_finish)
                                    : getString(R.string.moj_broj_dialog_next_round),
                        (d, w) -> {
                            if (jePoslednja) zavrsiIgru();
                            else sledecarRunda();
                        })
                .show();
    }

    /**
     * Poziva se kada igrač pritisne Potvrdi sa tačnim ili dovoljno bliskim odgovorom,
     * ili kada shake u fazi 2 zavrsi rundu.
     *
     * @param r rezultat evaluacije, {@code null} ako je runda predata bez unosa
     */
    private void onRundaZavrsena(MojBrojLogic.IzrazRezultat r) {
        faza = 0;
        boolean jePoslednja = (trenutnaRunda >= MAX_ROUNDS);

        String naslov  = (r != null && r.validan && (int) Math.round(r.rezultat) == trazeniBroj)
                ? getString(R.string.moj_broj_dialog_correct_title)
                : getString(R.string.moj_broj_dialog_near_title);
        String poruka  = (r != null && r.validan)
                ? getString(R.string.moj_broj_dialog_near_msg,
                            (int) Math.round(r.rezultat), trazeniBroj)
                : getString(R.string.moj_broj_dialog_timeout_msg, trazeniBroj);

        // Ako je tačan odgovor → posebna poruka
        if (r != null && r.validan && (int) Math.round(r.rezultat) == trazeniBroj) {
            poruka = getString(R.string.moj_broj_dialog_correct_msg, (int) Math.round(r.rezultat));
        }

        final String finalPoruka = poruka;
        new AlertDialog.Builder(this)
                .setTitle(naslov)
                .setMessage(finalPoruka)
                .setCancelable(false)
                .setPositiveButton(
                        jePoslednja ? getString(R.string.moj_broj_dialog_finish)
                                    : getString(R.string.moj_broj_dialog_next_round),
                        (d, w) -> {
                            if (jePoslednja) zavrsiIgru();
                            else sledecarRunda();
                        })
                .show();
    }

    private void sledecarRunda() {
        trenutnaRunda++;
        pokreniRundu();
    }

    // =========================================================================
    // Dijalog: predaj
    // =========================================================================

    private void showGiveUpDialog() {
        new AlertDialog.Builder(this)
                .setTitle(getString(R.string.moj_broj_dialog_give_up_title))
                .setMessage(getString(R.string.moj_broj_dialog_give_up_msg))
                .setPositiveButton(getString(R.string.moj_broj_dialog_give_up_yes), (d, w) -> {
                    otkaziTimere();
                    setResult(RESULT_CANCELED);
                    finish();
                })
                .setNegativeButton(getString(R.string.moj_broj_dialog_give_up_no), null)
                .show();
    }

    // =========================================================================
    // Završetak igre
    // =========================================================================

    private void zavrsiIgru() {
        Intent result = new Intent();
        result.putExtra(EXTRA_BODOVI, ukupnoBodova);
        setResult(RESULT_OK, result);
        finish();
    }

    // =========================================================================
    // Generisanje brojeva
    // =========================================================================

    /**
     * Generiše skup od 6 dostupnih brojeva:
     * 4 jednocifrena (1–9), 1 iz {10,15,20}, 1 iz {25,50,75,100}.
     */
    private int[] generisi6Brojeva() {
        int[] mali   = {10, 15, 20};
        int[] veliki = {25, 50, 75, 100};

        List<Integer> lista = new ArrayList<>();
        for (int i = 0; i < 4; i++) lista.add(1 + random.nextInt(9));
        lista.add(mali[random.nextInt(mali.length)]);
        lista.add(veliki[random.nextInt(veliki.length)]);
        Collections.shuffle(lista, random);

        int[] niz = new int[lista.size()];
        for (int i = 0; i < lista.size(); i++) niz[i] = lista.get(i);
        return niz;
    }

    private void prikaziBrojeve(int[] brojevi) {
        for (int i = 0; i < tvBrojevi.length; i++) {
            String v = String.valueOf(brojevi[i]);
            tvBrojevi[i].setText(v);
            btnBrojevi[i].setText(v);
        }
    }

    // =========================================================================
    // Pomoćne metode
    // =========================================================================

    private void appendToIzraz(String token) {
        if (faza != 2) return;
        izraz.append(token);
        osvežiIzraz();
    }

    private void osvežiIzraz() {
        etIzraz.setText(izraz.toString());
    }

    private void azurirajHeader() {
        tvRound.setText(getString(R.string.moj_broj_round_label, trenutnaRunda));
        azurirajScore();
    }

    private void azurirajScore() {
        tvScore.setText(getString(R.string.moj_broj_score_label, ukupnoBodova));
    }

    private void otkaziAutoStop() {
        if (autoStopTimer != null) {
            autoStopTimer.cancel();
            autoStopTimer = null;
        }
    }

    private void otkaziRunduTimer() {
        if (rundaTimer != null) {
            rundaTimer.cancel();
            rundaTimer = null;
        }
    }

    private void otkaziTimere() {
        otkaziAutoStop();
        otkaziRunduTimer();
    }
}

package com.example.slagalica.util;

import android.content.Context;
import android.hardware.Sensor;
import android.hardware.SensorEvent;
import android.hardware.SensorEventListener;
import android.hardware.SensorManager;

import androidx.annotation.NonNull;

/**
 * Utility klasa koja detektuje shake gest putem akcelerometra uređaja.
 *
 * <p>Upotreba u Activity:</p>
 * <pre>
 *   private ShakeDetector shakeDetector;
 *
 *   {@literal @}Override protected void onResume() {
 *       super.onResume();
 *       shakeDetector.start();
 *   }
 *
 *   {@literal @}Override protected void onPause() {
 *       super.onPause();
 *       shakeDetector.stop();
 *   }
 * </pre>
 *
 * <p>Nikad ne pozivati {@code start()}/{@code stop()} u {@code onCreate()}/{@code onDestroy()} —
 * senzori troše bateriju i moraju se pauzirati kada Activity nije vidljiv.</p>
 */
public class ShakeDetector implements SensorEventListener {

    // -------------------------------------------------------------------------
    // Konstante
    // -------------------------------------------------------------------------

    /** Prag ubrzanja iznad gravitacije koji se smatra shake gestom (m/s²). */
    private static final float SHAKE_THRESHOLD = 12.0f;

    /** Minimalni vremenski razmak između dva uzastopna shake-a (ms). */
    private static final long SHAKE_COOLDOWN = 1000L;

    // -------------------------------------------------------------------------
    // Callback interfejs
    // -------------------------------------------------------------------------

    /** Callback koji se poziva kada se detektuje shake gest. */
    public interface OnShakeListener {
        /**
         * Pozvano na UI thread-u kada akcelerometar detektuje shake
         * koji prelazi {@link #SHAKE_THRESHOLD} i prošao je {@link #SHAKE_COOLDOWN}.
         */
        void onShake();
    }

    // -------------------------------------------------------------------------
    // Polja
    // -------------------------------------------------------------------------

    private final SensorManager  sensorManager;
    private Sensor               accelerometer;
    private final OnShakeListener listener;

    /** Timestamp poslednjeg detektovanog shake-a (ms), 0 ako još nije bilo. */
    private long lastShakeTime = 0L;

    // -------------------------------------------------------------------------
    // Konstruktor
    // -------------------------------------------------------------------------

    /**
     * Kreira novi {@link ShakeDetector}.
     *
     * @param ctx      Context (Activity ili Application) — koristi se samo za SensorManager
     * @param listener callback koji se poziva pri svakom shake gestu
     */
    public ShakeDetector(@NonNull Context ctx, @NonNull OnShakeListener listener) {
        this.sensorManager = (SensorManager) ctx.getSystemService(Context.SENSOR_SERVICE);
        this.listener      = listener;
    }

    // -------------------------------------------------------------------------
    // Lifecycle
    // -------------------------------------------------------------------------

    /**
     * Registruje listener na akcelerometar. Pozivati u {@code onResume()}.
     *
     * <p>Ako uređaj nema akcelerometar, metoda ne radi ništa —
     * shake detektovanje neće biti dostupno.</p>
     */
    public void start() {
        if (sensorManager == null) return;
        accelerometer = sensorManager.getDefaultSensor(Sensor.TYPE_ACCELEROMETER);
        if (accelerometer != null) {
            sensorManager.registerListener(this, accelerometer, SensorManager.SENSOR_DELAY_UI);
        }
    }

    /**
     * Odjavljuje listener sa akcelerometra. Pozivati u {@code onPause()}.
     *
     * <p>Uvek pozivati ovu metodu da se spreči curenje memorije i bespotrebna
     * potrošnja baterije kada Activity nije u fokusu.</p>
     */
    public void stop() {
        if (sensorManager != null) {
            sensorManager.unregisterListener(this);
        }
    }

    // -------------------------------------------------------------------------
    // SensorEventListener
    // -------------------------------------------------------------------------

    /**
     * Poziva se pri svakoj promeni vrednosti akcelerometra.
     *
     * <p>Izračunava ukupno ubrzanje i poredi ga sa pragom.
     * Ako gForce prelazi {@link #SHAKE_THRESHOLD} i prošlo je više od
     * {@link #SHAKE_COOLDOWN} od poslednjeg shake-a, poziva {@link OnShakeListener#onShake()}.</p>
     *
     * @param event SensorEvent sa vrednostima na osama x, y, z (m/s²)
     */
    @Override
    public void onSensorChanged(@NonNull SensorEvent event) {
        float ax = event.values[0];
        float ay = event.values[1];
        float az = event.values[2];

        // Ukupna magnitude ubrzanja
        double totalAcceleration = Math.sqrt((double) ax * ax + (double) ay * ay + (double) az * az);

        // Oduzimamo gravitaciju da dobijemo neto ubrzanje od korisnikovog pokreta
        double gForce = totalAcceleration - SensorManager.GRAVITY_EARTH;

        if (gForce > SHAKE_THRESHOLD) {
            long now = System.currentTimeMillis();
            if (now - lastShakeTime > SHAKE_COOLDOWN) {
                lastShakeTime = now;
                listener.onShake();
            }
        }
    }

    /**
     * Poziva se pri promeni tačnosti senzora. Nije relevantno za shake detekciju.
     */
    @Override
    public void onAccuracyChanged(Sensor sensor, int accuracy) {
        // Nije potrebno pratiti promenu tačnosti za shake detekciju
    }
}

/**
 * seed_firestore.js
 * Puni Firestore kolekciju "korakPoKorak" sa zadacima za igru "Korak po korak".
 *
 * Pokretanje (iz root foldera projekta):
 *   npm install firebase-admin   ← samo prvi put
 *   node seed_firestore.js
 *
 * Preduslov: serviceAccountKey.json mora biti u istom folderu kao ova skripta.
 */

const admin = require('firebase-admin');
const serviceAccount = require('./serviceAccountKey.json');

admin.initializeApp({
    credential: admin.credential.cert(serviceAccount)
});

const db = admin.firestore();

// -------------------------------------------------------------------------
// Podaci za seed
// -------------------------------------------------------------------------

